mapper.select:
SELECT OBJECTID as objectId, NAME as tableNameCh,TABLENAME as tableNameEn,SJXJBM as resourceIdentify from
CLASSIFY_INTERFACE_ALL_DATE
where SJXJBM is not null and objectstate = 1

    and (PRIMARYORGANIZATIONCH = #{primaryClassifyCh} or SECONDARYORGANIZATIONCH = #{primaryClassifyCh})


    and PRIMARYORGANIZATIONCH = #{primaryClassifyCh}


    and SECONDARYORGANIZATIONCH = #{secondaryClassifyCh}


    and 'JZCODEGASJZZFL'||SJYJFLCODENAME||SJEJFLCODENAME = #{classifyid}


    and 'JZCODEGASJZZFL'||SJYJFLCODENAME||SJEJFLCODENAME||SJSJFLCODENAME = #{classifyid}


    and
    (upper(NAME) like upper('%' || #{search} || '%') or
    upper(TABLENAME) like upper('%' || #{search} || '%') or
    upper(SJXJBM) like upper('%' || #{search} || '%')
    )

select SJXJBM as resourceIdentify,YYYXTJSGS as manufacturer,SJZYSQDWMC as authority from SYNLTE.PUBLIC_DATA_INFO where
SJXJBM is not null
and (YYYXTJSGS is not null or SJZYSQDWMC is not null)

    and YYYXTJSGS = #{manufacturer}


    and SJZYSQDWMC = #{authority}

SELECT SJXJBM as resourceIdentify ,TABLE_TYPE||'.'||TABLE_PROJECT as storageLocation,TABLE_ALL_COUNT as dataNum, register_state as registerState, resourceId FROM ( SELECT j.SJXJBM,j.TABLE_TYPE,j.TABLE_PROJECT,j.TABLE_ALL_COUNT,j.register_state,resourceId, row_number ( ) over ( PARTITION BY lower( TABLE_PROJECT ), upper( TABLE_NAME_EN ) ORDER BY STATISTICS_TIME DESC ) AS rnn FROM table_organization_assets j WHERE PRIMARY_ORGANIZATION_CH = #{primaryClassifyCh}
and SECONDARY_ORGANIZATION_CH = #{secondaryClassifyCh}
and THREELEVEL_ORGANIZATION_CH = #{secondaryClassifyCh}
and (upper(TABLE_TYPE) in ('ODPS','CLICKHOUSE') or upper(TABLE_TYPE) like '%HIVE%') and STATISTICS_TIME >= trunc (sysdate - #{daysAgo}) ) h WHERE h.rnn =1
